const orders = $input.all();
const totalOrders = orders.length;
const totalRevenue = orders.reduce((sum, o) => sum + (parseFloat(o.json.Amount) || 0), 0);
const avgOrder = totalOrders > 0 ? (totalRevenue / totalOrders).toFixed(2) : 0;
const today = new Date().toLocaleDateString('en-IN', {timeZone: 'Asia/Kolkata', dateStyle: 'full'});

const message = `📊 *Daily Sales Report*
${today}

` +
  `📦 Total Orders: *${totalOrders}*
` +
  `💰 Total Revenue: *₹${totalRevenue.toFixed(2)}*
` +
  `📈 Avg Order Value: *₹${avgOrder}*

` +
  (totalOrders === 0 ? `⚠️ No orders today. Try sharing your catalog!` : `🚀 Great work! Keep it up!`);

return [{ json: { message, totalOrders, totalRevenue } }];
